    function popcountDepth(x) {
        if (x === 1) return 0;
        if (memo.has(x)) return memo.get(x);
        const count = bin(x).split('').filter(c => c === '1').length;
        const depth = 1 + popcountDepth(count);
        memo.set(x, depth);
        return depth;
