from functools import lru_cache

def solve(n: int, k: int) -> int:
    @lru_cache(maxsize=None)
    def popcount_depth(x: int) -> int:
        depth = 0
        while x != 1:
            x = bin(x).count('1')
            depth += 1
        return depth

    count = 0
    for x in range(1, n + 1):
        if popcount_depth(x) == k:
            count += 1
    return count
